package com.example.cms.operations.software; import org.springframework.jdbc.core.JdbcTemplate;import org.springframework.stereotype.Service;import java.util.*; @Service public class SoftwareComplianceService{private final JdbcTemplate jdbc; public SoftwareComplianceService(JdbcTemplate jdbc){this.jdbc=jdbc;} public List<Map<String,Object>> licenses(){return jdbc.queryForList("select * from software_components order by name");} public List<Map<String,Object>> vulnerabilities(){return jdbc.queryForList("select * from vulnerability_records order by severity desc");}}
